const Q_PHYSICS_2022_MODEL_III=[{"id": "objective>Physics>2022 Model III>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is stored by a dry Leclanche cell?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electrical power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electric current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemical energy </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A dry Leclanche cell stores chemical energy. This is because it is a type of battery, and batteries store energy chemically. When the battery is connected in a circuit, the stored chemical energy is converted into electrical energy.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2022 Model III>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A magnetic field is a region in which a magnetic force can be detected</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A line of force is a line along which a magnetic north pole would tend to move if it were free.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic fields are scalar quantities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutral points are obtained where the Earth's magnetic field is exactly equal and opposite to that due to a magnet. </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Magnetic fields are not scalar quantities, they are vector quantities. This is because they have both magnitude and direction. A scalar quantity only has magnitude. Therefore, the statement 'Magnetic fields are scalar quantities' is not correct.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2022 Model III>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a transverse wave?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">radio waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sound waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water waves</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sound waves are not transverse waves, they are longitudinal waves. This is because the particles in sound waves vibrate parallel to the direction of the wave, not perpendicular to it as in transverse waves. Therefore, sound waves are the correct answer.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2022 Model III>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radio station broadcasts at a frequency of 800kHz. If the speed of light in air is 3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, calculate the wavelength of the radio wave.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">375m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">475m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">273m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wavelength of a wave can be calculated using the formula λ = c/f, where c is the speed of light and f is the frequency. Substituting the given values, we get λ = (3 × 10^8 m/s) / (800 × 10^3 Hz) = 375 m.</div>", "topic": "ELECTROMAGNETIC SPECTRUM"}, {"id": "objective>Physics>2022 Model III>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a fundamental unit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fundamental units are the basic units of measurement in physics, which include kilogram (kg) for mass, meter (m) for length, and second (s) for time. Newton meter (Nm) is not a fundamental unit but a derived unit, which is a combination of the fundamental units.</div>", "topic": "MEASUREMENTS AND UNITS : FUNDAMENTAL PHYSICAL QUANTITIES"}, {"id": "objective>Physics>2022 Model III>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the smallest division marked on a standard meter rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.01 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A standard meter rule is divided into centimeters (cm), and each centimeter is further divided into 10 millimeters (mm). Since 1 mm is equal to 0.1 cm, the smallest division is 0.1 cm.</div>", "topic": "MEASUREMENTS AND UNITS : LIMITATIONS OF EXPERIMENTAL MEASUREMENTS"}, {"id": "objective>Physics>2022 Model III>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not an ohmic conductor ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silicon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metals</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ohmic conductor is a conductor that obeys Ohm's law, which states that the current through a conductor between two points is directly proportional to the voltage across the two points. Silicon is a semiconductor, not an ohmic conductor. Copper, silver, and metals in general are examples of ohmic conductors.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2022 Model III>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the peak value of a voltage whose r.m.s value is 200V</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">282.84V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">482.84V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">382.84V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">162.84V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The peak value of a sinusoidal waveform (like AC voltage) is √2 times the root mean square (RMS) value. So, the peak value of a voltage whose RMS value is 200V is 200V * √2 = 282.84V.</div>", "topic": "SIMPLE A. C. CIRCUITS : PEAK AND R.M.S. VALUES"}, {"id": "objective>Physics>2022 Model III>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not true for equilibrium under the action of non-parallel coplanar forces.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the algebraic sum of the horizontal components of the forces must be zero </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the algebraic sum of the vertical components of the forces must be zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the algebraic sum of the moments of all the forces about any axis perpendicular to the plane of the forces must be zero.</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the algebraic sum of the horizontal components of the forces must not be zero</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For an equilibrium of action under non-parallel coplanar forces: <br/> - the algebraic sum of the horizontal components of the forces must be zero <br/> - the algebraic sum of the vertical components of the forces must be zero <br/> -the algebraic sum of the moments of all the forces about any axis perpendicular to the plane of the forces must be zero.</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2022 Model III>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The direction of a light ray changes as it passes from one medium to another. The phenomenon is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Refraction is the change in direction of a wave passing from one medium to another caused by its change in speed</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2022 Model III>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An a.c voltage of amplitude 2.0 volts is connected to an RLC series circuit. If the resistance in the circuit is 5Ω, and the inductance and capacitance are 3mH and 0.05μF respectively, calculate the resonance frequency f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">13kHz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14kHz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">23kHz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18kHz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2π√LC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2π√(3×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>×5×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2π√(15×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>)</td></tr></table></div> <br/> f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 12994.95Hz <br/> f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> = 13kHz</div>", "topic": "SIMPLE A. C. CIRCUITS : RESONANCE AND RESONANCE FREQUENCY"}, {"id": "objective>Physics>2022 Model III>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the potential at a point 60cm from a charge of 5 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span>C.  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(Take</td><td style=\"text-align:center;\">1<hr size=\"1\" />4πε</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</td></tr></table></div></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">750V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">350V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">450V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250V</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The potential at a point due to a charge is given by the formula V = kQ/r. Substituting the given values, we get V = 750V.</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2022 Model III>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gives rise to the line spectra observed in atoms?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kinetic energy of moving atoms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potential energy of an electron inside an atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Change of an electron from a higher to a lower energy level in the atom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Disturbed proton in the nucleus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Change of an electron from a higher to a lower energy level in the atom, gives rise to the line spectra observed in atoms</div>", "topic": "ELEMENTARY MODERN PHYSICS : ENERGY LEVELS AND SPECTRA"}, {"id": "objective>Physics>2022 Model III>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the angle of declination is a place is 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>E, calculate the true geographic bearing if the compass reads N45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>E</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N65<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N75<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>E</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The angle of declination is the angle between the magnetic north and the true north. If the angle of declination is 20 degrees east, it means that the magnetic north is 20 degrees east of the true north. Therefore, if the compass reads N45 degrees E, the true geographic bearing would be N65 degrees E.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>2022 Model III>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a mechanical wave </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light waves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">water waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sound waves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">waves on string</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mechanical waves require a medium to propagate. Light waves, unlike sound waves, water waves, and waves on a string, do not require a medium to propagate. They can travel through a vacuum, which is not possible for mechanical waves.</div>", "topic": "WAVES : CLASSIFICATION"}, {"id": "objective>Physics>2022 Model III>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal rod whose length at 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C is 15m is heated to 55<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C, and its length increased to 15.02m. Calculate the linear expansivity of the rod.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.89 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.89 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.89 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.89 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>(θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15.02-15<hr size=\"1\" />15(55-40)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.02<hr size=\"1\" />15(15)</td></tr></table></div> <br/> α = 8.89 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2022 Model III>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a wind instrument</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Trombone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guitar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Piano</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bells</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A wind instrument is a musical instrument that makes sound by causing air to vibrate, usually within a tube. Of the given options, the trombone is a wind instrument. </div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2022 Model III>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Spring balance is used to measure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">length</div>", "<div style=\"font-family:Cambria;font-size:17px;\">time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">height</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A spring balance is a type of weighing scale used for measuring the weight or force exerted on it. It works on the principle of Hooke's Law, which states that the force exerted on a spring is directly proportional to the amount it is stretched.</div>", "topic": "MEASUREMENTS AND UNITS : MASS"}, {"id": "objective>Physics>2022 Model III>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the effect of using split-rings in a simple d.c. motor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the direction of rotation of the coil is reversed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the current in the coil flows in the same direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the current in the coil becomes alternating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the direction of force on the coil is reversed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a simple DC motor, split rings are used as a commutator. A commutator is a device that reverses the direction of current flow through the coil at the exact moment when the coil crosses the magnetic field lines. This ensures that the current in the coil always flows in the same direction, which in turn ensures that the force on the coil (and thus the direction of rotation of the coil) remains constant.</div>", "topic": "MAGNETIC FIELD : THE D. C. MOTOR"}, {"id": "objective>Physics>2022 Model III>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If positive charges are induced on an electroscope and a positively charged rod is brought near the cap of the electroscope, the leaves will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diverge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">close up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">become positively charged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">become negatively charged</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a positively charged rod is brought near the cap of an electroscope that has positive charges induced on it, the leaves of the electroscope will diverge or spread apart. This is because like charges repel each other. The positive charges on the rod repel the positive charges on the electroscope, causing the leaves to spread apart.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2022 Model III>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the electric field intensity in vacuum at a distance of 30cm from a charge of 8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>C.  <br/> (Take <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4πε</span> = 9 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">9</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electric field intensity E in a vacuum at a distance r from a point charge q is given by the formula E = kq/r^2, where k is Coulomb's constant (9 × 10^9 Nm^2/C^2). Substituting the given values into the formula gives E = (9 × 10^9 Nm^2/C^2) * (8 × 10^-5 C) / (0.3 m)^2 = 8 × 10^6 N/C.</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2022 Model III>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If detergent is added to a liquid, the surface tension </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">doubles</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Detergents are surfactants, which reduce the surface tension of a liquid. The surface tension of a liquid is the cohesive force between liquid molecules, and when detergent is added, it disrupts these forces, thereby reducing the surface tension.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2022 Model III>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass of 15kg is moving at a constant velocity of 8ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. Calculate its kinetic energy.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">460J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">480J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">580J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">540J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The kinetic energy of an object can be calculated using the formula KE = 1/2 * m * v^2, where m is the mass of the object and v is its velocity. Substituting the given values, we get KE = 1/2 * 15kg * (8ms^-1)^2 = 480J. Therefore, the kinetic energy of the object is 480J.</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2022 Model III>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describes the direction of an induced e.m.f.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lenz's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Faraday's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ohm's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coulomb's law</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lenz's law states that the induced e.m.f is in such a direction as to oppose the motion or change producing it.</div>", "topic": "ELECTROMAGNETIC INDUCTION : LENZ’S LAW"}, {"id": "objective>Physics>2022 Model III>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric heater, rated 25V 60A, is used to heat 2kg of a liquid from 45<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C to 48<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C in 2 seconds. Find the specific heat capacity of the liquid.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">500Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">450Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">400Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">300Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H = mC(θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) <br/> H = IVt <br/> IVt = mC(θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) <br/> 25×60×2 = 2 × C × (48-45) <br/> 3000 = 6C <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3000<hr size=\"1\" />6</td></tr></table></div> <br/> C = 500Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  </div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2022 Model III>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has the longest wavelength?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gamma rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Visible light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">microwaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radio waves</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wavelength of a wave is inversely proportional to its frequency. This means that waves with higher frequencies have shorter wavelengths, and vice versa. In the electromagnetic spectrum, gamma rays have the highest frequency and therefore the shortest wavelength, followed by visible light, microwaves, and radio waves. Therefore, radio waves have the longest wavelength among the options given.</div>", "topic": "ELECTROMAGNETIC SPECTRUM"}, {"id": "objective>Physics>2022 Model III>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a method of producing charges ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">by contact</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by electrostatic induction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by friction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">by heating</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Charges can be produced by several methods, including by contact (also known as conduction), by electrostatic induction, and by friction. These methods involve the transfer or redistribution of charges between objects. However, heating is not a method of producing charges. While heating can cause certain effects related to charges, such as increasing the rate of electron movement in a conductor, it does not produce charges by itself.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>2022 Model III>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the wavelength of an electron moving at a velocity of 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. <br/> [h = 6.62 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>kgs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 9.1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-31</span>kg]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.06 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.06 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span>m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.06 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span>m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.06 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wavelength of an electron can be calculated using the de Broglie equation, λ = h / (m * v), where h is Planck's constant, m is the mass of the electron, and v is the velocity of the electron. Substituting the given values, we get λ = 6.62 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span> m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>kgs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> / (9.1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-31</span>kg * 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) = 6.06 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span>m.</div>", "topic": "ELEMENTARY MODERN PHYSICS : WAVE-PARTICLE PARADOX DUALITY OF MATTER"}, {"id": "objective>Physics>2022 Model III>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which part of a camera functions like the retina of  the human eye?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">film</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aperture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shutter</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part of a camera that functions like the retina of the human eye is the film. The film in a camera is where the image is formed, just like the retina in the human eye.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2022 Model III>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Calculate the equivalent capacitance of the circuit in the above diagram, if C1 = 5μF, C2 = 15μF, C3 = 10μF, C4 = 3μF</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.43μF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.43μF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.53μF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.63μF</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a series combination <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />C1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />C2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />C3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />C4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />5</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />15</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />10</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6+2+3+10<hr size=\"1\" />30</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">21<hr size=\"1\" />30</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30<hr size=\"1\" />21</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />7</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.43μF</td></tr></table></div></div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2022 Model III>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A metre rule is found to balance at 50cm mark. When a body of mass 50kg is suspended at the 10cm mark, the balance  point is found to be 24cm mark. Find the mass of the ruler. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14.9kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">26.9kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.9kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">34kg</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taking the moment at P, <br/> 50(24-10) = M(50-24) <br/> 50(14) = 26M <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">700<hr size=\"1\" />26</td></tr></table></div> <br/> M = 26.9kg</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2022 Model III>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The motion of a simple pendulum is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oscillatory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotational</div>", "<div style=\"font-family:Cambria;font-size:17px;\">translational</div>", "<div style=\"font-family:Cambria;font-size:17px;\">random</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The motion of a simple pendulum is oscillatory. A simple pendulum moves back and forth about a fixed point, which is the definition of oscillatory motion.</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2022 Model III>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not true about x-rays.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are electromagnetic waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they ionise gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they have low frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they have very short wavelength</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X-rays are a type of electromagnetic radiation, similar to light but with much higher energy. They have the ability to ionize gases, which means they can remove tightly bound electrons from the orbit of an atom, causing the atom to become charged or ionized. X-rays have a very short wavelength, which is what allows them to penetrate matter and makes them useful for medical imaging. However, they do not have a low frequency. In fact, they have a very high frequency, which is inversely proportional to their short wavelength. Therefore, the statement 'they have low frequency' is not true about x-rays.</div>", "topic": "ELEMENTARY MODERN PHYSICS : X-RAYS"}, {"id": "objective>Physics>2022 Model III>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a natural source of light</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Moon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stars</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Torchlight</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural sources of light are those that occur naturally and are not man-made. The Sun and stars are natural sources of light because they emit light due to the nuclear reactions taking place within them. The Moon is also considered a natural source of light, although it does not produce its own light but reflects light from the Sun. On the other hand, a torchlight is a man-made, or artificial, source of light. It produces light when electrical energy is converted into light energy. Therefore, 'Torchlight' is not a natural source of light.</div>", "topic": "LIGHT ENERGY : SOURCE OF LIGHT"}, {"id": "objective>Physics>2022 Model III>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The terminal velocity of a ball-bearing falling through a viscous fluid is reached when the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">upthrust is equal to the weight of the ball</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ball accelerate uniformly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upthrust is equal to the velocity of the ball</div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity is uniform</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Terminal velocity is the constant speed that a freely falling object eventually reaches when the resistance of the medium through which it is falling prevents further acceleration. This happens when the force due to gravity (which causes the object to accelerate downwards) is balanced by the resistance or drag force (which opposes the motion). For a ball-bearing falling through a viscous fluid, this occurs when the upthrust (buoyancy force) and the drag force from the fluid are equal to the weight of the ball. At this point, the ball stops accelerating and falls at a constant speed, or terminal velocity. Therefore, the terminal velocity is reached when the 'velocity is uniform'.</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>2022 Model III>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the mass of copper deposited on the cathode of a copper voltameter if a current of 0.84A is passed through it for 20 minutes (e.c.e of copper = 3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>gC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.33g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.63g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.83g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.33g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M = ZIt <br/> M = 3.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> × 0.84 × (20 × 60) <br/> M = 0.33g</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2022 Model III>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mercury does not wet glass because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cohesion in mercury is greater than the adhesion of mercury to glass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adhesion of mercury to glass is greater than cohesion in the mercury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adhesion is equal to cohesion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no cohesion in the mercury</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the cohesion in mercury is greater than the adhesion of the mercury to glass, which makes the mercury molecules stick together and does not wet glass.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2022 Model III>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the fundamental frequency of a closed pipe organ on a day when the speed of sound is 640ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is 160Hz, then the length of the pipe is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.1m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />f</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">640<hr size=\"1\" />160</td></tr></table></div> <br/> λ = 4m <br/> for a closed pipe <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">4</td></tr></table></div> <br/> L = 1m</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : FREQUENCY OF A NOTE EMITTED BY AIR COLUMNS"}, {"id": "objective>Physics>2022 Model III>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are used to dope a pure semiconductor to get a p-type semiconductor. <br/> I. Arsenic <br/> II. Indium <br/> III. Aluminium  <br/> IV. Boron</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II,III and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I,II,III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Indium, Aluminium and Boron are group III elements that act as acceptors for p-type semiconductor while arsenic is a group V element that acts as donor for n-type semiconductor.</div>", "topic": "INTRODUCTORY ELECTRONICS : N-TYPE AND P-TYPE SEMI-CONDUCTORS"}, {"id": "objective>Physics>2022 Model III>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following phenomenon is called photoelectric effect ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High energy electrons impinge on a metallic anode which then emits photons.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A high energy photon emits photons at it slowed down.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A metal absorbs quanta of light and then emits electrons.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Two electrons are created from a quantum of light.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photoelectric effect is defined as the ejection of electrons from a metal plate when light falls on it.</div>", "topic": "ELEMENTARY MODERN PHYSICS : PHOTOELECTRIC EFFECTS"}];
